if (Array.isArray(msg.payload)) {
    return msg; // It's an array, proceed
} else {
    node.error("API did not return an array. Payload: " + JSON.stringify(msg.payload));
    return null; // Not an array, stop the flow
}

// Get the trained clusters from global context
const clusters = global.get('price_fluctuation_clusters') || [];

// Read previous prices into a constant. Do not modify this object.
const lastPrices = global.get('last_known_prices') || {};

// Create a new, empty object to store the prices from the current run.
const newPrices = {};

const enriched_payload = [];
const sql_queries = [];
const alerts_payload = []; // Array for alert-worthy events

if (clusters.length === 0) {
    node.warn("Clusters have not been calculated yet. Skipping classification.");
    msg.payload.forEach(coin => {
        coin.fluctuation_category = 'pending_model';
        coin.percentage_change = 0;
        enriched_payload.push(coin);
        sql_queries.push({ topic: `INSERT INTO coingecko_history (coin_id, name, symbol, current_price) VALUES ('${coin.id}', '${coin.name.replace(/'/g, "''")}', '${coin.symbol}', ${coin.current_price});` });
        newPrices[coin.id] = coin.current_price;
    });
} else {
    msg.payload.forEach(coin => {
        const currentPrice = coin.current_price;
        const lastPrice = lastPrices[coin.id];
        let percentageChange = 0;
        let fluctuationCategory = 'new_coin';

        if (lastPrice && lastPrice !== 0) {
            percentageChange = ((currentPrice - lastPrice) / lastPrice) * 100;

            // Use the absolute value of the change for clustering
            const absPercentageChange = Math.abs(percentageChange);

            let minDistance = Infinity;
            clusters.forEach(cluster => {
                const distance = Math.abs(cluster.centroid[0] - absPercentageChange);
                if (distance < minDistance) {
                    minDistance = distance;
                    fluctuationCategory = cluster.name;
                }
            });
        }

        coin.fluctuation_category = fluctuationCategory;
        coin.percentage_change = percentageChange;
        enriched_payload.push(coin);

        sql_queries.push({ topic: `INSERT INTO coingecko_history (coin_id, name, symbol, current_price) VALUES ('${coin.id}', '${coin.name.replace(/'/g, "''")}', '${coin.symbol}', ${currentPrice});` });

        newPrices[coin.id] = currentPrice;

        // this event triggers an alert
        if (fluctuationCategory === 'small') {
            alerts_payload.push(coin);
        }
    });
}

// Save the completely new price object to the global context
global.set('last_known_prices', newPrices);

// Output 1: SQL queries to save data
// Output 2: Enriched data for the UI
// Output 3: Alerts for large fluctuations
return [{ payload: sql_queries }, { payload: enriched_payload }, { payload: alerts_payload }];

const coin = msg.payload;
const timestamp = new Date().toLocaleString('el-GR');

// Set the routing key
msg.amqp_routingKey = `notifications.${coin.id}`;

// Format for easy reading
msg.topic = `ALERT: Small Fluctuation for ${coin.name}`;
msg.payload = `At ${timestamp}, ${coin.name} showed a small price fluctuation. `;
msg.payload += `Current Price: $${coin.current_price.toFixed(2)}, `;
msg.payload += `Change (5 min): ${coin.percentage_change.toFixed(2)}%`;

// Format for logging to a file
msg.log_entry = `${new Date().toISOString()},${coin.id},${coin.name},${coin.current_price},${coin.percentage_change}`;

return msg;

// msg.payload is the full array of coins with fluctuation info
// Assign based on the fluctuation category
msg.payload.forEach(coin => {

    coin.current_price = '$' + coin.current_price.toFixed(2);

    switch (coin.fluctuation_category) {
        case 'small':
            coin.rowClass = 'success'; // small, stable changes
            break;
        case 'medium':
            coin.rowClass = 'warning'; // medium changes
            break;
        case 'large':
            coin.rowClass = 'danger'; // large, volatile changes
            break;
        default:
            coin.rowClass = 'info'; // new coins or pending model
            break;
    }
});
return msg;

msg.topic = `
CREATE TABLE IF NOT EXISTS coingecko_history (
    entry_id INTEGER PRIMARY KEY AUTOINCREMENT,
    coin_id TEXT NOT NULL,
    name TEXT,
    symbol TEXT,
    current_price REAL NOT NULL,
    timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
);`;
return msg;

const coinId = String(msg.payload).toLowerCase();

const coinNameMap = {
    'bitcoin': 'Bitcoin',
    'ethereum': 'Ethereum',
    'tether': 'Tether',
    'binancecoin': 'BNB',
    'solana': 'Solana',
    'staked-ether': 'Lido Staked Ether',
    'usd-coin': 'USD Coin',
    'ripple': 'XRP',
    'dogecoin': 'Dogecoin',
    'tron': 'Tron'
};

msg.topic = `
    SELECT 
        strftime('%H:%M', timestamp) as time_label,
        current_price
    FROM coingecko_history
    WHERE coin_id = '${coinId}'
    ORDER BY timestamp DESC
    LIMIT 100;
`;

msg.coin_name = coinNameMap[coinId] || coinId;
return msg;

const data = Array.isArray(msg.payload) ? msg.payload.slice().reverse() : [];

if (data.length === 0 || !data[0].time_label || !data[0].current_price) {
    node.warn("No historical data found for this coin.");
    return null;
}

const labels = data.map(row => row.time_label);
const values = data.map(row => row.current_price);

msg.payload = [{
    series: [msg.coin_name || "Unknown Coin"],
    data: [values],
    labels: labels
}];

return msg;

const clusterMaker = global.get('clusters');

if (!clusterMaker) {
    node.error("Clusters module not available. Was it initialized?");
    return;
}

const historicalData = msg.payload;
if (!historicalData || historicalData.length < 20) { // Need sufficient data
    node.warn("Not enough historical data to run clustering. Need at least 20 records.");
    return;
}

// 1. Group prices by coin_id
const pricesByCoin = historicalData.reduce((acc, row) => {
    if (!acc[row.coin_id]) {
        acc[row.coin_id] = [];
    }
    acc[row.coin_id].push(row.current_price);
    return acc;
}, {});

// 2. Calculate all historical percentage changes
const allPercentageChanges = [];
for (const coin_id in pricesByCoin) {
    const prices = pricesByCoin[coin_id];
    for (let i = 1; i < prices.length; i++) {
        const lastPrice = prices[i - 1];
        const currentPrice = prices[i];
        if (lastPrice !== 0) {
            const change = Math.abs(((currentPrice - lastPrice) / lastPrice) * 100);
            allPercentageChanges.push([change]); // Format for clusterMaker
        }
    }
}

if (allPercentageChanges.length < 3) {
    node.warn("Not enough price changes to create 3 clusters.");
    return;
}

// 3. Configure and run clustering
clusterMaker.k(3); // 3 clusters: small, medium, large
clusterMaker.iterations(100);
clusterMaker.data(allPercentageChanges);
const clusters = clusterMaker.run();

// 4. Sort clusters by centroid value (low to high)
clusters.sort((a, b) => a.centroid[0] - b.centroid[0]);

// 5. Label clusters and store globally
clusters[0].name = 'small';
clusters[1].name = 'medium';
clusters[2].name = 'large';

global.set('price_fluctuation_clusters', clusters);

node.log("K-means clustering model updated.");
msg.payload = {
    message: "Clustering model successfully updated",
    clusters_found: 3,
    total_datapoints: allPercentageChanges.length,
    clusters: clusters
}

return msg;

// K-means implementation
function KMeans() {
    this._k = 3;
    this._iterations = 100;
    this._data = [];
    this._clusters = [];

    this.k = function(k) { this._k = k; return this; };
    this.iterations = function(n) { this._iterations = n; return this; };
    this.data = function(data) { this._data = data; return this; };

    this.initCentroids = function() {
        this._clusters = [];
        // To avoid picking the same point, shuffle a copy
        const uniquePoints = Array.from(new Set(this._data.map(JSON.stringify)), JSON.parse);
        for (let i = 0; i < this._k; i++) {
            const randomIndex = Math.floor(Math.random() * uniquePoints.length);
            this._clusters.push({ centroid: uniquePoints[randomIndex].slice(), points: [] });
            uniquePoints.splice(randomIndex, 1); // Ensure unique centroids
        }
    };

    this.assignPoints = function() {
        this._clusters.forEach(c => c.points = []);
        this._data.forEach(point => {
            let minDist = Infinity;
            let clusterIndex = 0;
            this._clusters.forEach((cluster, i) => {
                const dist = Math.abs(cluster.centroid[0] - point[0]);
                if (dist < minDist) {
                    minDist = dist;
                    clusterIndex = i;
                }
            });
            this._clusters[clusterIndex].points.push(point);
        });
    };

    this.updateCentroids = function() {
        let changed = false;
        this._clusters.forEach(cluster => {
            if (cluster.points.length > 0) {
                const sum = cluster.points.reduce((acc, p) => acc + p[0], 0);
                const newCentroid = sum / cluster.points.length;
                if(newCentroid !== cluster.centroid[0]) {
                    cluster.centroid[0] = newCentroid;
                    changed = true;
                }
            } 
        });
        return changed;
    };

    this.run = function() {
        this.initCentroids();
        for (let i = 0; i < this._iterations; i++) {
            this.assignPoints();
            if(!this.updateCentroids()) {
                // centroids didn't change
                break;
            };
        }
        return this._clusters;
    };
}

// Create and store the K-means object in the global context
const clusterMaker = new KMeans();
global.set('clusters', clusterMaker);

msg.payload = "KMeans module initialized";
return msg;
